noncompliant:
// Wrong order: typedef after type
int typedef T;

// Wrong order: double before long
double long d;

// Wrong order: char after unsigned
char unsigned ch;

// Wrong order: signed after long
long signed int i;

compliant:
// Correct order: typedef before type
typedef int T;

// Correct order: long before double
long double d;

// Correct order: unsigned before char
unsigned char ch;

// Correct order: signed before long
signed long int i;
